import jwt
from datetime import datetime, timedelta
SECRET_KEY = 'yoursecretkey' # replace this with your secret key or use environment variable if you want to keep it in the source control 
ALGORITHM  = 'HS256'  
def create_access_token(userID: str , role :str):   
     payload = {         
         "exp": datetime.utcnow() + timedelta(days=0, seconds=180),  # expiration time set to one hour from now          
         "iat": datetime.utcnow(),  
         "sub": userID ,   
        'role': role         
     }     
      
     return jwt.encode(payload, SECRET_KEY, algorithm=ALGORITHM)  # encode the payload with your secret key and HS256 as a method of encryption